# Also poll for token continuously for 90s - maybe cash opens mark docs
Write-Output '=== Watching ProStore log for fresh JWT 90s ==='
$log='C:\Users\user\AppData\Local\Prostore\Logs\2026-07-15.log'
$startLen=(Get-Item $log).Length
$deadline=(Get-Date).AddSeconds(90)
$found=$null
while((Get-Date) -lt $deadline -and -not $found){
  Start-Sleep 3
  $tail=Get-Content $log -Tail 30 -Encoding Default -EA SilentlyContinue
  foreach($line in $tail){
    if($line -match 'simpleSignIn' -or ($line -match '"token":"(eyJ[^"]+)"' -and $line -match 'product_group')){
      if($line -match '"token":"(eyJ[^"]+)"'){
        $found=$Matches[1]
        "GOT TOKEN len=$($found.Length)"
        Set-Content C:\Users\Public\crpt_token.txt $found
        break
      }
    }
  }
}
if(-not $found){ 'no new token in 90s' }
